// This demo is GPU-rendered via the sea-surface primitive (afl_ext-inspired,
// MIT). There is no meaningful 2D lift for an infinite water heightfield;
// the 3D SceneData is hand-crafted to showcase the new sea-shading branch
// in FLY 3D (fresnel atmosphere reflection + subsurface scattering + ACES).
export const render = (ctx) => {
  ctx.fillStyle = '#0a223d';
  ctx.fillRect(0, 0, ctx.canvas.width, ctx.canvas.height);
  ctx.fillStyle = '#aab';
  ctx.font = '14px sans-serif';
  ctx.fillText('Open ocean (3D-only demo — switch to FLY 3D)', 24, 48);
};
